+static void vi_visual_attrib(char *s, int row)
+{
+	if (!vi_visual || !s)
+		return;
+	int ar = vi_vrow, ao = vi_voff;
+	int cr = xrow,   co = xoff;
+	if (ar > cr || (ar == cr && ao > co)) {
+		swap(&ar, &cr);
+		swap(&ao, &co);
+	}
+	if (row < ar || row > cr)
+		return;
+	if (!led_attsb)
+		sbuf_make(led_attsb, sizeof(led_att) * 16)
+	led_att la;
+	la.att = SYN_RV;
+	la.s = s;
+	ren_state *r = ren_position(s);
+	int rn1 = r->n - 1;
+	int o_beg, o_end;
+	if (vi_visual == 'V') {
+		o_beg = 0;
+		o_end = rn1;
+	} else if (vi_visual == 'b') {
+		o_beg = MIN(vi_voff, xoff);
+		o_end = MAX(vi_voff, xoff);
+	} else if (ar == cr) {
+		o_beg = ao; o_end = co;
+	} else if (row == ar) {
+		o_beg = ao; o_end = lbuf_eol(xb, row, 1);
+	} else if (row == cr) {
+		o_beg = 0;
+		o_end = co;
+	} else {
+		o_beg = 0;
+		o_end = lbuf_eol(xb, row, 1);
+	}
+	o_beg = MAX(0, MIN(o_beg, rn1));
+	o_end = MAX(0, MIN(o_end, rn1));
+	for (int o = o_beg; o <= o_end; o++) {
+		if (row == xrow && o == xoff)
+			continue;
+		la.off = o;
+		sbuf_mem(led_attsb, &la, (int)sizeof(la))
+	}
+}
